    bubbleSort(arr) {
        let n = arr.length;

        // Outer loop runs from the end towards the beginning
        for (let i = n - 1; i >= 0; i--) {
            // Inner loop iterates up to the i-th index
            for (let j = 0; j <= i - 1; j++) {
                // If current element is greater than the next element, swap them
                if (arr[j] > arr[j + 1]) {
                    let temp = arr[j + 1];
                    arr[j + 1] = arr[j];
                    arr[j] = temp;
                }
            }
        }

