    bubbleSort(arr) {
        let n = arr.length;

        // Outer loop runs from end of array towards the beginning
        for (let i = n - 1; i >= 0; i--) {
            let didSwap = false; // To check if any swapping happens in this pass

            // Inner loop compares adjacent elements
            for (let j = 0; j < i; j++) {  
                // If current element is greater than next, swap them
                if (arr[j] > arr[j + 1]) {
                    // Swap arr[j] and arr[j+1]
                    let temp = arr[j];
                    arr[j] = arr[j + 1];
                    arr[j + 1] = temp;

                    didSwap = true; // Mark that a swap occurred
                }
            }

            // If no swaps happened, the array is already sorted â break early
            if (!didSwap) {
                break;
            }
        }

        // Print the sorted array
        console.log("After Using Bubble Sort:");
        console.log(arr.join(" "));
    }
}

